import { Field as FieldPrimitive } from '@ark-ui/react/field';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Textarea.module.css';

const Textarea = forwardRef<
  ComponentRef<typeof FieldPrimitive.Textarea>,
  ComponentProps<typeof FieldPrimitive.Textarea>
>(function Textarea({ autoresize, className, ...props }, ref) {
  return (
    <FieldPrimitive.Textarea
      ref={ref}
      {...props}
      data-scope="field"
      data-part="textarea"
      data-slot="textarea-root"
      data-autoresize={autoresize ? '' : undefined}
      className={clsx(styles.root, normalizeClassName(className))}
      autoresize={autoresize}
    />
  );
});

export { Textarea };

@layer ui.components {
  .root {
    box-sizing: border-box;
    width: var(--textarea-width, 100%);
    max-width: var(--textarea-max-width, none);
    min-height: var(--textarea-min-height, 6rem);
    margin: 0;
    border: var(--textarea-border-width, var(--border-width-sm)) var(--textarea-border-style, solid)
      var(--textarea-border-color, var(--color-border));
    border-radius: var(--textarea-radius, var(--radius-md));
    padding: var(--textarea-padding-y, 0.5rem) var(--textarea-padding-x, 0.875rem);
    background-color: var(--textarea-bg, var(--color-background));
    color: var(--textarea-color, var(--color-foreground));
    font: inherit;
    font-size: var(--textarea-font-size, var(--text-md));
    line-height: var(--textarea-line-height, var(--line-height-text-md));
    outline: var(--textarea-focus-ring-width, var(--textarea-border-width, var(--border-width-sm)))
      solid transparent;
    outline-offset: var(--textarea-focus-ring-offset, -1px);
    resize: var(--textarea-resize, vertical);
    transition:
      border-color var(--textarea-transition, var(--transition-default)),
      outline-color var(--textarea-transition, var(--transition-default)),
      opacity var(--textarea-transition, var(--transition-default));
  }

  .root::placeholder {
    color: var(--textarea-placeholder-color, var(--color-muted-foreground));
  }

  .root:focus-visible {
    outline-color: var(--textarea-focus-ring-color, var(--color-ring));
  }

  .root:is([data-invalid], [aria-invalid='true']) {
    border-color: var(--textarea-border-color-invalid, var(--color-destructive));

    &:focus-visible {
      outline-color: var(--textarea-border-color-invalid, var(--color-destructive));
    }
  }

  .root:is([disabled], [data-disabled]) {
    pointer-events: none;
    opacity: var(--textarea-disabled-opacity, var(--opacity-disabled));
  }

  .root:is(:read-only, [data-readonly]) {
    background-color: var(--textarea-readonly-bg, var(--textarea-bg, var(--color-background)));
    color: var(--textarea-readonly-color, var(--textarea-color, var(--color-foreground)));
  }

  .root[data-autoresize] {
    overflow-y: hidden;
  }
}
